import { MapContainer, TileLayer } from "react-leaflet";
import { useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [position, setPosition] = useState([20, 77]);
  const [flightData, setFlightData] = useState(null);

  // 🔑 PUT YOUR API KEY HERE
  const API_KEY = "91e3efea2cb047fc37276c702ea01cda";

  const fetchFlight = async () => {
  try {
    const res = await fetch(
      `https://api.aviationstack.com/v1/flights?access_key=91e3efea2cb047fc37276c702ea01cda&flight_iata=${flightNo}`
    );

   setFlights(res.data);
      setSelected(null);
    } catch (err) {
      console.error(err);
      alert('Error fetching flight data');
    }
  };

  return (
    <div className="container">
      <h1 className="title">✈️ Flight Tracker Pro</h1>

      <div className="search-box">
        <input
          placeholder="Enter Callsign (e.g. QTR8964)"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
        <button onClick={fetchFlights}>Track</button>
      </div>

      <FlightMap flights={flights} selected={selected} />

      <div className="cards">
        {flights.map((f, i) => (
          <div
            key={i}
            className={`card ${selected === f ? 'active' : ''}`}
            onClick={() => setSelected(f)}
          >
            <h3>{f.callsign}</h3>
            <p>{f.country}</p>
          </div>
        ))}
      </div>

      {selected && (
        <div className="details">
          <h2>✈️ {selected.callsign}</h2>
          <p><b>Country:</b> {selected.country}</p>
          <p><b>Latitude:</b> {selected.latitude}</p>
          <p><b>Longitude:</b> {selected.longitude}</p>
          <p><b>Altitude:</b> {Math.round(selected.altitude)}</p>
          <p><b>Velocity:</b> {Math.round(selected.velocity)}</p>
          <p><b>ICAO24:</b> {selected.icao24}</p>
        </div>
      )}
    </div>
  );
}
